func TestFiatShamirChallengeParity(t *testing.T) {
	// Synthetic but deterministic inputs. Distinct points so a bind-order
	// regression cannot be masked by aliasing.
	var vk curplonk.VerifyingKey
	vk.S[0] = genG1(1)
	vk.S[1] = genG1(2)
	vk.S[2] = genG1(3)
	vk.Ql = genG1(4)
	vk.Qr = genG1(5)
	vk.Qm = genG1(6)
	vk.Qo = genG1(7)
	vk.Qk = genG1(8)
	vk.Qcp = []kzg.Digest{genG1(9), genG1(10), genG1(11)}

	publicInputs := make([]fr.Element, 5)
	for i := range publicInputs {
		publicInputs[i] = genFr(uint64(100 + i))
	}

	lro := [3]curve.G1Affine{genG1(20), genG1(21), genG1(22)}
	bsb22 := []curve.G1Affine{genG1(30), genG1(31)}
	z := genG1(40)
	h := [3]curve.G1Affine{genG1(50), genG1(51), genG1(52)}

	gammaRef, betaRef, alphaRef, zetaRef := referenceChallenges(
		t, &vk, publicInputs, lro, bsb22, z, h,
	)

	// GPU path — drive the same transcript through the GPU helpers exactly
	// as gpuProver does (see deriveGammaBeta / buildZAndCommit /
	// computeQuotientAndCommit in prove.go).
	fs := fiatshamir.NewTranscript(sha256.New(), "gamma", "beta", "alpha", "zeta")
	require.NoError(t, bindPublicData(fs, "gamma", &vk, publicInputs))
	gammaGPU, err := deriveRandomness(fs, "gamma", &lro[0], &lro[1], &lro[2])
	require.NoError(t, err)
	betaGPU, err := deriveRandomness(fs, "beta")
	require.NoError(t, err)
	alphaDeps := make([]*curve.G1Affine, 0, len(bsb22)+1)
	for i := range bsb22 {
		alphaDeps = append(alphaDeps, &bsb22[i])
	}
	alphaDeps = append(alphaDeps, &z)
	alphaGPU, err := deriveRandomness(fs, "alpha", alphaDeps...)
	require.NoError(t, err)
	zetaGPU, err := deriveRandomness(fs, "zeta", &h[0], &h[1], &h[2])
	require.NoError(t, err)

	require.True(t, gammaRef.Equal(&gammaGPU),
		"gamma diverged from gnark CPU FS pattern: ref=%s gpu=%s", gammaRef.String(), gammaGPU.String())
	require.True(t, betaRef.Equal(&betaGPU),
		"beta diverged: ref=%s gpu=%s", betaRef.String(), betaGPU.String())
	require.True(t, alphaRef.Equal(&alphaGPU),
		"alpha diverged: ref=%s gpu=%s", alphaRef.String(), alphaGPU.String())
	require.True(t, zetaRef.Equal(&zetaGPU),
		"zeta diverged: ref=%s gpu=%s", zetaRef.String(), zetaGPU.String())
}

