// TestFiatShamirBatchOpenParity exercises gpuBatchOpen's KZG-folding FS
// instance against gnark-crypto's kzg.BatchOpenSinglePoint. The two are run
// on identical synthetic inputs sharing a synthetic SRS. When the folding
// gamma matches byte-for-byte, the quotient commitment H is identical;
// any FS drift produces a different H.
func TestFiatShamirBatchOpenParity(t *testing.T) {
	// Synthetic KZG SRS: G1[i] = [i+1]·G. Not a valid powers-of-tau SRS, but
	// kzg.Commit just performs an MSM over pk.G1[:len(poly)] — both
	// BatchOpenSinglePoint and gpuBatchOpen consume the same SRS, so the
	// shared bias cancels and H equality reduces to FS-gamma equality.
	const srsSize = 64
	pkG1 := make([]curve.G1Affine, srsSize)
	for i := range pkG1 {
		pkG1[i] = genG1(uint64(i))
	}
	srsPK := kzg.ProvingKey{G1: pkG1}

	// Three polynomials of varying length, deterministic coefficients.
	polys := make([][]fr.Element, 3)
	polys[0] = make([]fr.Element, 16)
	polys[1] = make([]fr.Element, 12)
	polys[2] = make([]fr.Element, 8)
	for i := range polys {
		for j := range polys[i] {
			polys[i][j] = genFr(uint64(1000*i + j))
		}
	}

	digests := make([]curve.G1Affine, len(polys))
	for i := range polys {
		d, err := kzg.Commit(polys[i], srsPK)
		require.NoError(t, err)
		digests[i] = d
	}

	point := genFr(7)

	// Evaluate each poly at `point` (Horner) — gpuBatchOpen consumes these
	// as inputs; BatchOpenSinglePoint computes them internally from the
	// same coefficients, so the two must agree.
	claimedValues := make([]fr.Element, len(polys))
	for i, p := range polys {
		var v fr.Element
		for j := len(p) - 1; j >= 0; j-- {
			v.Mul(&v, &point)
			v.Add(&v, &p[j])
		}
		claimedValues[i] = v
	}

	dataTranscript := []byte{0xde, 0xad, 0xbe, 0xef, 0x01, 0x23, 0x45, 0x67}

	cpuProof, err := kzg.BatchOpenSinglePoint(
		polys, digests, point, sha256.New(), srsPK, dataTranscript,
	)
	require.NoError(t, err)

	gpuCommit := func(p []fr.Element) (curve.G1Affine, error) {
		return kzg.Commit(p, srsPK)
	}
	gpuProof, err := gpuBatchOpen(
		gpuCommit, polys, digests, claimedValues, point,
		sha256.New(), dataTranscript,
	)
	require.NoError(t, err)

	require.True(t, cpuProof.H.Equal(&gpuProof.H),
		"batch-open H differs — FS gamma folding diverged from gnark-crypto deriveGamma")
	require.Equal(t, len(cpuProof.ClaimedValues), len(gpuProof.ClaimedValues),
		"claimed values length mismatch")
	for i := range cpuProof.ClaimedValues {
		require.True(t, cpuProof.ClaimedValues[i].Equal(&gpuProof.ClaimedValues[i]),
			"claimed value %d mismatch", i)
	}
}
